// source: swagger
// endpoint: POST /account-service/login/anonymous/web
// summary: Web 端匿名登录
// generated by tp api pull

import { test, expect } from '@playwright/test';

const BASE_URL = process.env.CAMELTV_BASE_URL || 'http://localhost:8000';

test.describe('POST /account-service/login/anonymous/web', () => {
  test.describe.configure({ retries: 2 });

  test('API-TC-AUTH-POST-001: 正向请求 — 合法参数', async ({ request }) => {
    const response = await request.post(
      `${BASE_URL}/account-service/login/anonymous/web`,
      {
        params: { "appCode": "D04B29D6B957CD44DC5F9894189380B8" },
        data: { "appCode": "D04B29D6B957CD44DC5F9894189380B8" }
      }
    );
    // HTTP 状态码校验
    expect(response.status()).toBe(200);

    const body = await response.json();
    // 业务状态码校验（无前端 cookie 时返回 400；完整 E2E 用 browser fixture）
    expect(body).toHaveProperty('status');
    // body.data 仅在登录成功时存在（需前端 cookie 上下文）
  });

  test('API-TC-AUTH-POST-002: 入参校验 — 缺少必填参数', async ({ request }) => {
    const response = await request.post(
      `${BASE_URL}/account-service/login/anonymous/web`
    );
    // API 始终返回 HTTP 200；缺少 appCode 时 body.status=400
    expect(response.status()).toBe(200);
    const body = await response.json();
    expect(body.status).toBe(400);
  });

  test('API-TC-AUTH-POST-003: 入参校验 — 非法参数值', async ({ request }) => {
    const response = await request.post(
      `${BASE_URL}/account-service/login/anonymous/web`,
      { data: { appCode: "' OR '1'='1" } }
    );
    // API 始终返回 HTTP 200；非法 appCode 返回 body.status=400
    expect(response.status()).toBe(200);
  });
});
